import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import {
  LitElement,
  customElement,
  html,
  css,
  when,
  state,
} from "@umbraco-cms/backoffice/external/lit";
import type {
  FormSecurityForUser,
  FormsLicenseModel,
  UserSecurity,
} from "@umbraco-forms/generated";
import {
  LicensingService,
  SecurityService,
  UpdatesService,
} from "@umbraco-forms/generated";

const elementName = "forms-dashboard";

@customElement(elementName)
export class FormsDashboardElement extends UmbElementMixin(LitElement) {
  @state()
  private _showOverlay = false;

  @state()
  private _userSecurity?: UserSecurity;

  @state()
  private _currentVersion?: string;

  @state()
  private _status?: FormsLicenseModel;

  #create() {}

  async connectedCallback() {
    super.connectedCallback();

    let security: FormSecurityForUser;

    [this._status, this._currentVersion, security] =
      await Promise.all([
        LicensingService.getLicensingStatus(),
        UpdatesService.getUpdatesVersion(),
        SecurityService.getSecurityUserCurrentFormSecurity({
          includeFormFieldDetails: false,
        }),
      ]);

    this._userSecurity = security.userSecurity;
  }

  #hasUnrestrictedLicense() {
    return (
      this._status?.licenseLimitations.includes(
        "*not* associated with any ips or domains"
      ) ?? false
    );
  }

  #displayLicensedDomains() {
    if (!this._status?.validDomains) {
      return null;
    }

    return html`<ul>
      ${this._status.validDomains.split("|").map((d) => html`<li>${d}</li>`)}
    </ul>`;
  }

  render() {
    return html`
      ${when(
        this._showOverlay && this._userSecurity?.manageForms,
        () => html` <div class="umb-forms-install-overlay">
          <uui-button
            @click=${() => (this._showOverlay = false)}
            .label=${this.localize.term("general_close")}
          ></uui-button>

          <div>
            <div class="succes"></div>

            <h2>
              <strong
                >${this.localize.term(
                  "formsDashboard_installOverlayTitle"
                )}</strong
              >
            </h2>

            <p>
              ${this.localize.term("formsDashboard_installOverlayDescription")}
            </p>

            <div class="divider"></div>

            <uui-button
              color="positive"
              look="default"
              @click=${this.#create}
              label=${this.localize.term("formsDashboard_createAForm")}
            >
            </uui-button>
          </div>
        </div>`
      )}

      <forms-licensing .status=${this._status}></forms-licensing>

      ${when(
        this._currentVersion,
        () => html`<small
          >${this.localize.term(
            "formsDashboard_currentVersion",
            this._currentVersion
          )}</small
        >`
      )}

      <form-grid .config=${this._userSecurity}></form-grid>

      ${when(
        !this._status?.isTrial &&
          !this._status?.isInvalid &&
          !this.#hasUnrestrictedLicense(),
        () => html`<small
            >${this.localize.term("formsDashboard_licensedDomains")}:</small
          >
          <small>${this.#displayLicensedDomains()}</small>`
      )}
    `;
  }

  static styles = [
    css`
      :host {
        display: block;
        padding: var(--uui-size-layout-1);
      }

      @media (min-width: 1024px) {
        uui-box {
          display: block;
          max-width: calc(100% - 300px);
        }
      }

      form-grid {
        display: block;
        margin-bottom: 20px;
      }
    `,
  ];
}

export default FormsDashboardElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsDashboardElement;
  }
}
